module top_module(
    input clk,
    input reset,      // Synchronous active-high reset
    input up_down,    // Control signal to increment or decrement
    output [3:0] q);reg [3:0] unused_count;

    always @(posedge clk) begin
        if (reset) begin
            unused_count <= 4'b0;
        end else if (up_down) begin
            unused_count <= (unused_count == 4'b1111) ? 4'b0 : unused_count + 1;
        end else begin
            unused_count <= (unused_count == 4'b0000) ? 4'b1111 : unused_count - 1;
        end
    end

    assign q = unused_count;

endmodule
